class OfflineWebViewClient : WebViewClient() {

    private val offlineManager = OfflinePackageManager()

    override fun shouldInterceptRequest(
        view: WebView?,
        request: WebResourceRequest?
    ): WebResourceResponse? {
        val url = request?.url?.toString() ?: return null

